(14755, '0008', 'S0008-36', 'E 017a16', 'E 017r16', '', 'ceinelae [leg. cenelae] liac', 'a kind of stone', 'Cf. G 022b10=Hofman# 022b25 aa.\nCf. Bachellery (1964): 115.', '', 'abaddir', '', '', '', 36),
(14756, '0008', 'S0008-37', 'E 017b14', 'E 017v14', '', '.i. cnocc', 'i.e. ulcer', 'Cf. Bachellery (1964): 117.', '', 'ulcus', '', '', '', 37),
