(14758, '0008', 'S0008-39', 'E 018a28', '', '', '.)- dasian.', 'rough breathing', 'Cf. Bachellery (1964): 115.', '', 'spiritus asper', '', '', '', 39),
(14759, '0008', 'S0008-40', 'E 018b21', 'E 018v21', '', 'altor (Old Breton)', 'altar', 'Cf. 025b18 = Hofman# 025b35 ii.\nCf. Bachellery (1964): 117 „un scribe breton a sans doute trouvé la glose irl. sur son archétype et n’a eu qu’à enlever l’i pour obtenir la forme régulière v. br.“.', '', 'ara deorum', '', '', '', 40),
(14760, '0008', 'S0008-41', 'E 019b27', '', '', '.i. gerent g(r)ec', 'i.e. a gerund of (the) Greek words (= a Greek gerund)', 'The r is above the line.\nCf. G 027b18=Hofman# 027b40 nn.\nCf. Bachellery (1964): 117.', '', 'dictum a tribuendo quod νημηιν', '', '', '', 41),
(14761, '0008', 'S0008-42', 'E 020b10', 'E 020v10', '', '.i. file', 'i.e. which are', 'Cf. Bachellery (1964): 118.', '', 'Aliae fere omnes species i[n] nominibus', '', '', '', 42);
