(14938, '0003', 'S0003-1', '', '', '', '[Íb]thuss art ier cetharchait aidchi comhnart caur conbeba muccruime.', 'Art will drink it after forty nights, a mighty hero. He will die at Muccruime.', '', '', '', '', '', '', 14938),
(14939, '0003', 'S0003-2', '', '', '', 'Mac con maicc aui lugde loigde la sechtmain sephus fri.', 'Mac Con son of Lugaid Loígde\'s descendant who will strike for a week of days against', '', '', '', '', '', '', 14939),
(14940, '0003', 'S0003-3', '', '', '', 'Ferguss dubdetach con bebat breig det chatho con fri crinne cichuir.', 'Fergus Dubdétach. They will die in Breg. A tooth of battle. He will wage towards Crinne.', '', '', '', '', '', '', 14940),
(14941, '0003', 'S0003-4', '', '', '', 'Corbmac coten ibau ol sen sáim nía bephaid scoilicc bid an fear fuiri foilcfithus.', 'Corbmac will drink it, a drink of elders, a peaceful warrior. He will perish from a morsel of food. He will be a glorious man upon her. He will wash her.', '', '', '', '', '', '', 14941),
(14942, '0003', 'S0003-5', '', '', '', 'Ipthuss corpre comlond co flatha fir.', 'Corpre of combats will drink it with the truth of sovereignty', '', '', '', '', '', '', 14942),
(14943, '0003', 'S0003-6', '', '', '', 'Ailfithuss fiechri fill mora mide cichsot cen muir.', 'Fiechri will demand it. The treacheries of the great descendants of Mide. They will advance far from the sea.', '', '', '', '', '', '', 14943),
(14944, '0003', 'S0003-7', '', '', '', 'Conden daire drechlethan dailfa darb mís.', 'Dáire Drechtlethan will dispense it in a difficult month.', '', '', '', '', '', '', 14944),
(14945, '0003', 'S0003-8', '', '', '', 'Disngig fecho fer hætho ainb asa mesatar ciss.', 'Fécho will request it, unwitting man of territory whose tribute they will adjudge.', '', '', '', '', '', '', 14945),
(14946, '0003', 'S0003-9', '', '', '', 'Muiredach tírech trichtach tusnena nadmuim.', 'Muiredach Tírech for thirty years shall bind it with a bond.', '', '', '', '', '', '', 14946),
(14947, '0003', 'S0003-10', '', '', '', 'An chrimthand lethan lonn fuath fo cois.', 'Glorious Crimthand, broad and fierce, phantoms under foot.', '', '', '', '', '', '', 14947),
(14948, '0003', 'S0003-11', '', '', '', 'Con niell noifiter neirp catha crich.', 'Níell will be celebrated, boar(?) of battle of boundaries.', '', '', '', '', '', '', 14948),
(14949, '0003', 'S0003-12', '', '', '', 'Cu Loigaire lonn lenfetar inda tailcend (.i. Pat-) techt taige tarrsnae (.i. eacailsi) crainn (.i. bachl-) chromai beirtis blatha tua dind.', 'Fierce Loígaire will be grieved by the coming of the adze-heads. Transverse houses, crooked staves, they would bear flowers to his fort.', '', '\'will be grieved\' both Murphy and Murray without explaining. Perhaps more \'will be hindered, prevented\'?', '', '', '', '', 14949),
(14950, '0003', 'S0003-13', '', '', '', 'Cain cur corpre cotenibha hart han feal fuirri.', 'A fine hero, Corpre will drink it. A glorious, noble bear upon her.', '', '', '', '', '', '', 14950),
(14951, '0003', 'S0003-14', '', '', '', 'Feal ailill hiphtus.', 'Noble Ailill will drink it.', '', '', '', '', '', '', 14951),
(14952, '0003', 'S0003-15', '', '', '', 'Lund lugid rohole saoer siasstar fir nairm.', 'Fierce Lugaid of great noble drinking shall be approached, truth of weaponry.', '', '', '', '', '', '', 14952),
(14953, '0003', 'S0003-16', '', '', '', 'án fear for mac Ercéni (i muircertach).', 'A glorious man after Mac Ercéni will be', '', '', '', '', '', '', 14953),
(14954, '0003', 'S0003-17', '', '', '', 'Oengarb (.i. tuat-) gebthus gnoe gai gairb.', 'Óengarb. He will take it, beauty of a harsh spear.', '', '', '', '', '', '', 14954),
(14955, '0003', 'S0003-18', '', '', '', 'Gebthus aid an anruth.', 'Aed will seize it, glorious lord.', '', '', '', '', '', '', 14955),
(14956, '0003', 'S0003-19', '', '', '', 'Aed da(?)in biass bith.', 'Aed Allan who will strike a blow.', 'Aed using a subscript beneath E.', '', '', '', '', '', 14956),
(14957, '0003', 'S0003-20', '', '', '', 'Biad fuirri fir ndiarmada Disngig diermait dia rirsetar liss lundug han con fri irthine nacht.', 'Diermait\'s truth will be upon her. Diermait, by whom courts will be ruled, will request it. Glorious savage flame, he drove towards Irthine.', '', '', '', '', '', '', 14957),
(14958, '0003', 'S0003-21', '', '', '', 'Ailt fuir feachno.', 'A blade over her, Féchno.', '', '', '', '', '', '', 14958),
(14959, '0003', 'S0003-22', '', '', '', 'Fearr suibne', 'Better Suibne.', '', '', '', '', '', '', 14959),
(14960, '0003', 'S0003-23', '', '', '', 'Soer oengus.', 'Noble Óengus.', '', '', '', '', '', '', 14960),
(14961, '0003', 'S0003-24', '', '', '', 'han domnall.', 'Glorious Domnall.', '', '', '', '', '', '', 14961),
(14962, '0003', 'S0003-25', '', '', '', 'Discig blathmac Diarmaid auæ aleili (.i. diarmaid mac aodha slani) is e eblas in aige.', 'Blathmac, Diermait, grandson of the other, will request it. It is he who will celebrate the assembly.', '', '', '', '', '', '', 14962),
(14963, '0003', 'S0003-26', '', '', '', 'Flaith blai. flaith chinid. flaith echtach. helimm da .c. mbliadne mboie', 'Sovereignty of immunities, sovereignty of liabilities, vengeance-wreaking sovereignty of Élimm, which was for two hundred years.', '', '', '', '', '', '', 14963),
(14964, '0003', 'S0003-27', '', '', '', 'Ibthius snechta fina fhirfess. Flaith ho niell co nell.', '\'Snow of Wine\', who will pour out sovereignty from Niell to Niell, will drink it.', '', '', '', '', '', '', 14964),
(14965, '0003', 'S0003-28', '', '', '', 'Niell caich ua neill naiscther geill.', 'The Niell of each [is the] descendant of Niell whose hostages are bound.', '', '', '', '', '', '', 14965),
(14966, '0003', 'S0003-29', '', '', '', 'dothetha tein Ruad garg raithnech less bess tress mi for bliadni bebais muir mar domain dinib duabais díth.', 'A red, harsh fire of bracken will dwindle. A benefit which will be a struggle. A month and a year [for the one] who will die in the sea. To the generations of the great world, gloom, loss.', '', '\'who will die\' better \'he will die\'', '', '', '', '', 14966),
(14967, '0003', 'S0003-30', '', '', '', 'Flaith sessgdach (.i.) ier sloghaib sæ Bebaid fuil fritha heirr cath crueth dith ba[th].', 'Sovereignty of sixty years pursues hosts. He will die of a wound. He will injure them in a fierce battle. Loss, extinction.', '', '', '', '', '', '', 14967),
(14968, '0003', 'S0003-31', '', '', '', 'Bie[d] fuirri flann asail an oirb arusnene nertaib d[or]n d[o] giallaib.', 'Flann Asail will be upon her, glorious heir. He will betroth her by force of fists to hostages.', '', '', '', '', '', '', 14968),
(14969, '0003', 'S0003-32', '', '', '', 'Doscich furbaide (.i. brian) ferr cach fer fuirri Flaith ma[ic] mess maith li', 'Furbaide will request it, better than everyone [the] man who is over her. A youth\'s sovereignty, good judgement, splendour.', '', '', '', '', '', '', 14969),
(14970, '0003', 'S0003-33', '', '', '', 'Ánflaith fori mbia bith tr[omm] tuilldech dia mbebtar breig (.i. fergal) flaith cailig comnart confiastar fuiri.', 'An unking who will strike a heavy blow, a bastard by whom there will be death in Breg. The mighty sovereignty of \'the Cock\' will prevail over her.', '', '', '', '', '', '', 14970),
(14971, '0003', 'S0003-34', '', '', '', 'Biad fuirre glunsalach fine forderga a toeb tussness giallaib gebaid ross riris mumain maith nith cetni comburbech hirthinea hanflaith for temair.', '\'The Dirty-kneed One\'  will be upon her, a kindred whose flank is very red. He will spurn her with hostages. He will seize Ros. He will rule Mugain, victory in the same battle, the breaker of assemblies of lrthine, an unking over Tara.', '', '', '', '', '', '', 14971),
(14972, '0003', 'S0003-35', '', '', '', 'Dossnicfa fer fingalach esmbrethach hipthuss co derc domain Saxain imchil immus au chorcc eblai (.i. fland) is e ræthe mumain marlaithe hi temuir. Finit.', 'A kin-slaying man of unjust judgements will come to it. He will drink it to the very bottom. Very wicked Saxons. The descendant of Corcc will pursue them. He is the overlord of Munster of great princes in Tara.', '', '', '', '', '', '', 14972);
INSERT INTO `SENTENCES` (`ID`, `Text_ID`, `Text_Unit_ID`, `Locus1`, `Locus2`, `Locus3`, `Textual_Unit`, `Translation`, `Textual_Notes`, `Translation_Notes`, `Latin_Text`, `Translation_From_Latin`, `Variant_Readings`, `Subunit`, `Sort_ID`) VALUES
(16774, '0077', 'S0077-3', 'Bisagni_and_Warntjes_2008.97', 'Einsiedeln_Computus.001', '', 'De diebus menseis conputandis.\r\noin Kalendae\r\nailiu iiii Nonas\r\ntres iii Nonas\r\ncethirmat ii Nonas\r\ncoicet Nonae\r\nsesset viii Idus\r\nsechtmet vii Idus\r\noctmet vi Idus\r\nnomet v Idus\r\ndecmed . iiii Idus\r\noindeac iii Idus\r\nailiu deac ii Idus\r\ntres deac Idus\r\net reliqua.\r\nSic taliter enumeres omnium mensium dies.\r\n', 'Of the computation of days of the month\n\n[day] one - The Calends (i.e. first day of the Month)\nsecond [day] - fourth [day before the] Nones\nthird [day] - third [day before the] Nones\nfourth [day] - second [day before the] Nones\nfifth [day] - The Nones\nsixth [day] - eighth [day before the] Ides\nseventh [day] - seventh [day before the] Ides\neighth [day]  - sixth [day before the]  Ides\nninth [day] - fifth [day before the] Ides\ntenth [day]  - fourth [day before the]  Ides\n[day]  eleven - third [day before the]  Ides\ntwelfth [day] - second [day before the]  Ides\nthirteenth [day]  - The Ides\n\nEt cetera. \n\nSo you may count the days of all the months.', 'p. 97 col. a, ll. 11-29.', '', '-', '', '', '', 3),
(16775, '0077', 'S0077-4', 'Bisagni_and_Warntjes_2008.102-103', 'Einsiedeln_Computus.002', '', '.i. maá . triun . laigu . leut . ', 'that is, greater than one third, smaller than one half', 'p. 123, ll. 23-24', '', '-', '', '', '', 4);
INSERT INTO `SENTENCES` (`ID`, `Text_ID`, `Text_Unit_ID`, `Locus1`, `Locus2`, `Locus3`, `Textual_Unit`, `Translation`, `Textual_Notes`, `Translation_Notes`, `Latin_Text`, `Translation_From_Latin`, `Variant_Readings`, `Subunit`, `Sort_ID`) VALUES
(17931, '0077', 'S0077-1', 'Bisagni_and_Warntjes_2008.92', 'Einsidlensis_Computus.001', '', 'Dies proprie duas diuisiones habet: interdianum et nocturnum. Interdianum autem dicitur laithidę. Hic nihil addit praepositio vt quidam dicunt. Aliter interdianum etarlaithidę, .i. nox inter duos dies; Internocturnum etaraidchidę, .i. dies inter .ii. noctes.', 'A day, strictly speaking, contains two divisions: interdianum and nocturnum. Interdianum means “day-time”. Here the preposition (i.e. inter) does not add anything, as some people say. Alternatively, interdianum [means] “between day-times”, that is, the night between two days, [and] internocturnum [means] “between night-times”, that is, the day between two nights.', 'p 90, ll. 1-15. This is a bilingual text.', '', '', '', '', '', 1),
(17932, '0077', 'S0077-2', 'Bisagni_and_Warntjes_2008.94', 'Einsidlensis_Computus.002', '', 'Februarius dictus est a febris acris lupercorum. Hoc enim tempore acra febris fit quo parturiunt lupę 7 corui. unde scoti dicunt: dóth. dedúb.', 'February is so called from the heavy fevers of the Luperci. Indeed, heavy fever becomes manifest at this time, in which she-wolves and ravens give birth; for this reason the Irish say “brood of blackness”.', 'p. 93, ll. 31-34. The Irish text is incorporated into the Latin.', '', '', '', '', '', 2);
INSERT INTO `TEXT` (`ID`, `Text_ID`, `Title`, `Date`, `Dating_Criteria`, `Edition`, `MSS`, `Digital_MSS`, `Thes`, `Contributor`, `Created_Date`, `MS_Checked`, `Reason_Of_MS_Choice_And_Editorial_Policy`, `Reference`, `Sort_ID`) VALUES
(3, '0003', 'Baile_Chuinn', 'Text: c. 720; Dublin and Egerton MSS: 16th c. Date range 690-720 is used in ChronHib.', 'Text dates to c. 720 based on internal references to kings, see Bhreathnach 2005, 66. Dublin MS: by Aodh, wrote in house of Seán Ó Maolchonaire circa 1575. Dubhthach signed name on MS; Egerton MS: Written by Domhnall and Maghnus O Duibhdabhoirenn (Donall O\'Davoren) 16th c.', 'Murray & Bhreathnach 2005\r\nThe text here follows the reading of MS 23 N 10 as we disagree with Bhreathnach and Murray in several instances on editorial choice and normalisation.', 'Dublin, Royal Irish Academy MS 23 N 10, pp. 73–74; London, British Library, MS Egerton 88, f. 12va', '', '', 'Fangzhe Qiu', '2017/6/12', 'Yes', '', '', 3),
(8, '0008', 'Paris_Priscian', 'MS: 9th c. Date range 825-851 is used in ChronHib.', 'Scribe of MS: likely to have been \'a Breton Scribe working in a Carolingian centre\' (Bronner, 2013, 40; Hofman, 1996, I, 36). The glosses are from the \'first layer\' of glossing on Priscian (see VAQ) and therefore could be probably be dated earlier than the manuscript.', 'Bauer 2015a', 'Paris, Bibliothèque Nationale de France, Lat. 10290', '', '', 'Bernhard Bauer', 'previous', 'Yes', '', 'Bauer 2015b', 8),
(67, '0067', 'Epistle_of_Jesus', 'Date range for text 857-887 is used in ChronHib.', 'AU 887 records the coming of the Sunday Letter and Cáin Domnaig to Ireland. MS 23 P 16: (Leabhar Breac) early 15th c.; MS Harleian 5280, fo. 36a: Early 16th c.; MS 23 N 10: 16th c., Scribes: Aodh (the owner of the book), Dubthach and Tornae.; MS 1318 (The Yellow Book of Lecan), 14th-15th c.; MS 23 O 48a (Liber Flavus Fergusiorum) 15th c. ', 'O\'Keefe 1905;\r\nPOMIC', 'Dublin, Royal Irish Academy, MS 23 P 16, p. 202b; London, British Library, MS Harleian 5280, fo. 36a; Dublin, Royal Irish Academy, MS 23 N 10, p. 103; Dublin, Trinity College, MS 1318, col. 219, col. 957;  Dublin, Royal Irish Academy, MS 23 O 48a, fol. 45', '', '', '', '2018/10/1', '', '', '', 67);
INSERT INTO `TEXT` (`ID`, `Text_ID`, `Title`, `Date`, `Dating_Criteria`, `Edition`, `MSS`, `Digital_MSS`, `Thes`, `Contributor`, `Created_Date`, `MS_Checked`, `Reason_Of_MS_Choice_And_Editorial_Policy`, `Reference`, `Sort_ID`) VALUES
(77, '0077', 'Einsiedeln_Computus_Minor_Glosses', 'MS: 867-900, Text 689-719.', 'MS/Glosses: Bronner, 2013, 15: MS: \"IX. Jh., (2./)3. Drittel (ca. 874)\" (Bischoff, 1998, 242), late 9th cent. (Bisagni & Warntjes 2008, 79 & fn. 6), karolingische Minuskel; Text datiert zw. 689 und 719 (ID., 81, 89–91, 104)', '', 'Einsiedeln, Stiftsbibliothek, 321 (647)', '', '', 'Elliott Lash', '', '', '', 'Lash 2021', 77);
